### Load transfer data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
options(chromote.headless = "new")

yrs <- 2023:2025

portal <- purrr::map(yrs, ~ cfbfastR::cfbd_recruiting_transfer_portal(
  year = .x)) |> 
  dplyr::bind_rows() |> 
  dplyr::mutate(
    transfer_date = as.Date(transfer_date),
    transfer_month = lubridate::month(transfer_date, label = TRUE),
    transfer_year = lubridate::year(transfer_date),
    rating = as.numeric(rating),
    window = ifelse(transfer_month != "Apr", "Winter", "Spring"),
    position = ifelse(position == "ATH", "QB", position),
    position = forcats::fct_infreq(position) |> forcats::fct_rev(),
    rating_tier = dplyr::case_when(
      rating >= 0.95 ~ "Elite",
      rating >= 0.90 ~ "High",
      rating >= 0.85 ~ "Solid",
      TRUE ~ "Depth"
    )
  ) |> 
  dplyr::filter(!is.na(destination))

position_counts <- portal |>
  dplyr::filter(!is.na(origin), !is.na(destination)) |>
  dplyr::group_by(origin, destination, season, position) |>
  dplyr::summarise(n = dplyr::n(), .groups = "drop")

position_labels <- position_counts |>
  dplyr::mutate(label = paste0(n, " ", position)) |>
  dplyr::group_by(origin, destination, season) |>
  dplyr::summarise(
    n = sum(n),
    positions = paste(label, collapse = ", "),
    .groups = "drop"
  ) |>
  dplyr::arrange(-n)
```
