### Portal charts


::: {.cell}

```{.r .cell-code}
import_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Largest Transfer Portal Imports</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Most amount of players from one program to transfer to another program over past 3 seasons.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)

import_tbl <- position_labels |> 
    dplyr::filter(n > 7) |> 
    cbbplotR::gt_cbb_teams(origin, origin) |> 
    cbbplotR::gt_cbb_teams(destination, destination) |>
    dplyr::select(season, origin, destination, n, positions) |> 
    gt::gt() |> 
    gtUtils::gt_theme_gtutils() |> 
    gt::fmt_markdown(columns = c(origin, destination)) |> 
    gtExtras::gt_merge_stack(
      col1 = n,
      col2 = positions,
      palette = c("black", "#333333")
    ) |> 
    gtUtils::gt_column_subheaders(
      season = list(heading = "Season", subtitle = "Portal period"),
      origin = list(heading = "Origin", subtitle = "From where"),
      n = list(heading = "Players", subtitle = "w/Positions"),
      destination = list(heading = "Destination", subtitle = "To where"),
      heading_color = "black",
      subtitle_color = "gray"
  ) |> 
  gt::cols_align(columns = c(origin, destination, n),
                 align = "left") |> 
  gtExtras::gt_highlight_rows(
    rows = c(1, 2, 8),
    columns = "season",
    fill = "#C5C5FF",
    bold_target_only = TRUE,
    target_col = c(season),
  ) |> 
  gtExtras::gt_add_divider(
    columns = c(season, origin, destination),
    sides = "right",
    color = "black"
  ) |> 
   gt::tab_header(title = gt::html(import_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via cfbfastR + 247Sports.com, theme via {gtUtils}<hr>
        <b>Table by Chris at Bless your chart | Data as of May 12, 2025</b>"
      )
  ) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
   gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative")
      )
    ),
    locations = gt::cells_body(
      gt::everything()
    )
  ) |> 
  gt::tab_options(table.width = gt::px(775)) |> 
   gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc"))



gtUtils::gt_save_crop(
  import_tbl,
  file = "import_tbl.png",
  whitespace = 40,
  bg = "#FFFDF5"
)

import_tbl
