acc_plot_data <- acc_results_long |> 
  dplyr::arrange(team, date) |> 
  dplyr::mutate(
    win = as.integer(team_score > opp_score),
    loss = as.integer(team_score < opp_score)
  ) |>
  dplyr::group_by(team) |> 
  dplyr::mutate(
    cum_win = cumsum(win),
    cum_loss = cumsum(loss),
    win_diff = cum_win - cum_loss,
    cum_games = cum_win + cum_loss,
    cum_win_pct = cum_win / cum_games
  ) |> 
  dplyr::ungroup()

target_date <- as.Date("2025-05-14")

team_labels <- acc_plot_data |> 
  dplyr::arrange(desc(date), -contest_id) |> 
  dplyr::group_by(team) |> 
  dplyr::slice_max(order_by = date, n = 1) |> 
  dplyr::left_join(standings, by = c("team")) |> 
  dplyr::ungroup() |> 
  dplyr::group_by(cum_win_pct) |>
  dplyr::mutate(
    stagger = dplyr::row_number() - (dplyr::n() + 1) / 2,
    y_staggered = win_diff + stagger * 0.45
